	var btn_fence := _add_button(vbox, "+1 Zaun")
	btn_fence.pressed.connect(_give_item.bind("fence"))
	var btn_wall := _add_button(vbox, "+1 Wand")
	btn_wall.pressed.connect(_give_item.bind("wall"))
